import{_ as t,a as e}from"./chunks/频繁报错提示.B4wBXruJ.js";import{_ as a,o,c as l,a2 as r}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Limiti di frequenza per gli utenti","description":"","frontmatter":{},"headers":[],"relativePath":"it-IT/Safety/user-rate-limits.md","filePath":"it-IT/Safety/user-rate-limits.md","lastUpdated":1781962217000}'),d={name:"it-IT/Safety/user-rate-limits.md"};function n(s,i,p,u,c,m){return o(),l("div",null,[...i[0]||(i[0]=[r('<h1 id="limiti-di-frequenza-per-gli-utenti" tabindex="-1">Limiti di frequenza per gli utenti <a class="header-anchor" href="#limiti-di-frequenza-per-gli-utenti" aria-label="Permalink to &quot;Limiti di frequenza per gli utenti&quot;">​</a></h1><p>I limiti di frequenza controllano quanto spesso utenti normali o visitatori possono caricare file dalla homepage. Servono a evitare abusi sulle pagine di upload pubbliche.</p><p>Questa funzione riguarda solo gli upload dalla homepage. Gli upload admin e quelli fatti con API Token non sono limitati da queste regole.</p><h2 id="dove-configurare" tabindex="-1">Dove configurare <a class="header-anchor" href="#dove-configurare" aria-label="Permalink to &quot;Dove configurare&quot;">​</a></h2><p>Apri il pannello admin e vai a:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Upload Management -&gt; User Rate Limits</span></span></code></pre></div><p><img src="'+t+'" alt="Impostazioni limiti utente" loading="lazy"></p><h2 id="abilitare-i-limiti" tabindex="-1">Abilitare i limiti <a class="header-anchor" href="#abilitare-i-limiti" aria-label="Permalink to &quot;Abilitare i limiti&quot;">​</a></h2><p>Dopo aver attivato <code>Enable Rate Limits</code>, ImgBed tiene traccia degli upload recenti in base all&#39;indirizzo IP di chi carica.</p><p>Valori predefiniti:</p><table tabindex="0"><thead><tr><th>Impostazione</th><th>Default</th><th>Descrizione</th></tr></thead><tbody><tr><td>Finestra di rilevamento</td><td>1,5 ore</td><td>Quanto indietro contare i record di upload.</td></tr><tr><td>Numero massimo file</td><td>20</td><td>Numero massimo di file consentiti nella finestra.</td></tr><tr><td>Limite singolo file</td><td>20 MB</td><td>Dimensione massima di un file.</td></tr><tr><td>Limite totale upload</td><td>200 MB</td><td>Dimensione totale massima nella finestra.</td></tr></tbody></table><p>Per esempio, con finestra di 1,5 ore, 20 file, 20 MB per file e 200 MB totali, gli upload dallo stesso IP vengono bloccati appena uno dei limiti configurati viene superato.</p><h2 id="escludere-tipi-di-file" tabindex="-1">Escludere tipi di file <a class="header-anchor" href="#escludere-tipi-di-file" aria-label="Permalink to &quot;Escludere tipi di file&quot;">​</a></h2><p><code>Excluded upload file types</code> blocca agli utenti normali o visitatori il caricamento di categorie selezionate.</p><p>Categorie disponibili:</p><table tabindex="0"><thead><tr><th>Tipo</th><th>Descrizione</th></tr></thead><tbody><tr><td>Images</td><td>jpg, png, webp, gif e file immagine simili</td></tr><tr><td>Videos</td><td>mp4, webm, mov e file video simili</td></tr><tr><td>Audio</td><td>mp3, flac, wav e file audio simili</td></tr><tr><td>Documents</td><td>pdf, txt, md, docx e documenti simili</td></tr><tr><td>Other</td><td>File fuori dalle categorie sopra, come zip, rar, exe, apk</td></tr></tbody></table><p>Di default un tipo non selezionato è consentito.</p><p>Quando clicchi un tipo e viene evidenziato, quel tipo è bloccato.</p><p>Se <code>Other</code> è selezionato, i visitatori che caricano zip o rar verranno bloccati con un messaggio di tipo file non supportato.</p><h2 id="messaggi-di-blocco" tabindex="-1">Messaggi di blocco <a class="header-anchor" href="#messaggi-di-blocco" aria-label="Permalink to &quot;Messaggi di blocco&quot;">​</a></h2><p>Quando viene superato un limite, l&#39;utente vede un messaggio coerente:</p><p><img src="'+e+'" alt="Messaggio upload troppo frequente" loading="lazy"></p><table tabindex="0"><thead><tr><th>Scenario</th><th>Significato del messaggio</th></tr></thead><tbody><tr><td>Singolo file troppo grande</td><td>Il file è troppo grande e va compresso prima dell&#39;upload.</td></tr><tr><td>Tipo file bloccato</td><td>Questo tipo di file non è supportato. Rimuovilo e riprova.</td></tr><tr><td>Upload troppo frequenti</td><td>Gli upload recenti sono troppo frequenti; viene mostrato quando riprovare.</td></tr><tr><td>Dimensione totale troppo alta</td><td>La dimensione totale recente è troppo alta; viene mostrato quando riprovare.</td></tr></tbody></table><h2 id="quando-abilitarli" tabindex="-1">Quando abilitarli <a class="header-anchor" href="#quando-abilitarli" aria-label="Permalink to &quot;Quando abilitarli&quot;">​</a></h2><p>Abilita i limiti utente se la homepage di upload è accessibile pubblicamente.</p><p>Motivi comuni:</p><ul><li>temi upload massivi automatizzati.</li><li>vuoi limitare upload grandi da parte dei visitatori.</li><li>vuoi permettere agli utenti normali solo immagini, non archivi o installer.</li><li>vuoi mantenere l&#39;upload pubblico disponibile controllando il consumo di risorse.</li></ul><p>Se il sito è solo per te o solo gli amministratori possono caricare, puoi lasciare questa funzione disattivata.</p>',28)])])}const b=a(d,[["render",n]]);export{f as __pageData,b as default};
